def simulate(days, seed):
    random.seed(seed)
    cash=cash0
    cohorts=[c.copy() for c in small]
    ents=[e.copy() for e in ent]
    ent_events=initial_ent_events(days)
    active0=sum(c['n'] for c in cohorts if c['group']=='S2')
    market_cap=max(145000,random.gauss(164000,23000))
    cap_growth=max(0.00008,random.gauss(0.00040,0.00014))
    paid_lpd=max(0.007,min(0.022,random.lognormvariate(math.log(0.013),0.30)))
    net_rate=max(0.00055,min(0.00145,random.gauss(0.00100,0.00022)))
    conv_base=max(0.48,min(0.72,random.gauss(0.595,0.050)))
    mixA=max(0.18,min(0.36,random.gauss(0.265,0.035)))
    mixB=max(0.58,min(0.80,random.gauss(0.725,0.040)))
    if mixA+mixB>0.995: mixB=0.995-mixA
    macro_bad=max(0, random.gauss(0.055,0.035))
    support_repair=random.uniform(0.0,0.035)
    for d in range(DAY+1, DAY+days+1):
        rel=d-DAY
        active_s2=sum(c['n'] for c in cohorts if c['group']=='S2')
        cap=market_cap*((1+cap_growth)**rel)
        denom=max(0.05,1-active0/market_cap)
        rel_sat=max(0.02,min(1.25,(1-active_s2/cap)/denom))
        ad_s2=15000.0
        if active_s2>0.94*cap: ad_s2=12000.0
        if active_s2>0.975*cap: ad_s2=7000.0
        paid=max(0,random.gauss(ad_s2*paid_lpd*rel_sat, max(20,ad_s2*paid_lpd*0.35)))
        net=max(0,random.gauss(active_s2*net_rate*rel_sat, max(15,active_s2*net_rate*0.35)))
        leads=paid+net
        cv=conv_base + support_repair*min(1,rel/21)
        for bd,b in boosts:
            if d>=bd: cv+=min(0.045,b*0.10)
        cv-=macro_bad*min(1,rel/35)
        if random.random()<0.018: cv-=random.uniform(0.04,0.14)
        cv=max(0.56,min(0.90,random.gauss(cv,0.035)))
        new=leads*cv
        ma=max(0.30,min(0.58,random.gauss(mixA,0.04)))
        mb=max(0.38,min(0.68,random.gauss(mixB,0.04)))
        if ma+mb>0.995: mb=0.995-ma
        nA=new*ma; nB=new*mb; nC=max(0,new-nA-nB)
        cash += nA*small_first_cash('S2','A') + nB*small_first_cash('S2','B') + nC*small_first_cash('S2','C')
        cohorts += [{'n':nA,'seats':nA,'group':'S2','plan':'A','price':79.0,'mod':d%30,'age':0}, {'n':nB,'seats':nB,'group':'S2','plan':'B','price':159.0,'mod':d%30,'age':0}]
        if nC>0: cohorts.append({'n':nC,'seats':nC,'group':'S2','plan':'C','price':349.0,'mod':d%30,'age':0})
        def add_small(group, organic_rate, cv_start, cv_gain, bshare_mu, paid_leads=0.0):
            nonlocal cash, cohorts
            leads_g=max(0, random.gauss(active_s2*organic_rate*rel_sat + paid_leads, max(5,active_s2*organic_rate*0.35 + paid_leads*0.35)))
            cvg=max(0.0,min(0.75,random.gauss(cv_start + min(cv_gain, rel*cv_gain/21.0),0.08)))
            for bd,b in boosts:
                if d>=bd: cvg=min(0.80,cvg+min(0.05,b*0.09))
            newg=leads_g*cvg
            if newg<=0: return leads_g
            bshare=max(0.0,min(0.95,random.gauss(bshare_mu,0.14)))
            nb=newg*bshare; na=newg-nb
            cash += na*small_first_cash(group,'A') + nb*small_first_cash(group,'B')
            if na>0: cohorts.append({'n':na,'seats':na,'group':group,'plan':'A','price':recurring_price(group,'A'),'mod':d%30,'age':0})
            if nb>0: cohorts.append({'n':nb,'seats':nb,'group':group,'plan':'B','price':recurring_price(group,'B'),'mod':d%30,'age':0})
            return leads_g
        d7_ad_lpd=max(0.030,min(0.105,random.lognormvariate(math.log(0.062),0.32)))
        leads_extra=0
        leads_extra += add_small('D_S07',0.00105,0.38,0.06,0.965, paid_leads=35000*d7_ad_lpd)
        leads_extra += add_small('D_S04',0.00055,0.20,0.12,0.88)
        leads_extra += add_small('D_S03',0.00075,0.08,0.18,0.25)
        leads_extra += add_small('S1',0.00030,0.10,0.18,0.10)
        leads_extra += add_small('S3',0.00042,0.22,0.10,0.86)
        leads_extra += add_small('D_S06',0.00045,0.08,0.18,0.18)
        leads_extra += add_small('D_S10',0.00018,0.08,0.18,0.35)
        leads_extra += add_small('D_S05',0.00018,0.08,0.24,0.35)
        # New enterprise leads after day140; few close inside short horizons.
        lam=max(0,active_s2*0.00015*rel_sat)
        for _ in range(max(0,int(random.gauss(lam,max(1,math.sqrt(max(1,lam))))))):
            seats=max(100,random.gauss(1000,520)); p=max(0.015,min(0.12,random.gauss(0.055,0.035)))
            if random.random()<p:
                delay=max(12,int(random.gauss(35,18))); ev_day=d+delay
                if ev_day<=DAY+days:
                    plan='A' if random.random()<0.45 else ('C' if random.random()<0.20 else 'B')
                    price={'A':29.0,'B':39.0,'C':59.0}[plan]
                    ent_events.append({'day':ev_day,'seats':seats,'plan':plan,'price':price,'mod':ev_day%30,'group':'E3'})
        for ev in list(ent_events):
            if ev['day']==d:
                cash += ev['seats']*ev['price']
                ents.append({'group':ev['group'],'seats':ev['seats'],'n':1,'plan':ev['plan'],'price':ev['price'],'mod':d%30,'age':0})
                ent_events.remove(ev)
        quality_bonus=0
        for bd,b in boosts:
            if d>=bd: quality_bonus += min(0.055,b*0.10)
        for c in cohorts:
            if c['age']>0 and c['mod']==d%30 and c['n']>0:
                if c['group']=='S2':
                    if c['plan']=='A': base=0.78 + min(0.05,rel*0.0015) + quality_bonus - macro_bad*0.65
                    elif c['plan']=='B': base=0.945 + min(0.025,rel*0.0008) + quality_bonus*0.6 - macro_bad*0.30
                    else: base=0.91 + quality_bonus*0.8 - macro_bad*0.35
                    if active_s2>0.90*cap: base-=0.02
                elif c['group']=='D_S07': base=0.90+quality_bonus-macro_bad*0.25
                elif c['group'] in ('D_S04','S3','D_S05','D_S06','D_S10'): base=0.84+quality_bonus-macro_bad*0.25
                else: base=0.82+quality_bonus-macro_bad*0.25
                ret=max(0.68,min(0.992,random.gauss(base,0.035)))
                c['n']*=ret; c['seats']=c['n']; cash += c['n']*c['price']
            c['age']+=1
        for e in ents:
            if e['age']>0 and e['mod']==d%30 and e['seats']>0:
                eret=0.90 if e['plan']=='A' else (0.86 if e['price']<=49 else 0.78)
                eret += quality_bonus*1.0 - macro_bad*0.35
                eret=max(0.45,min(0.985,random.gauss(eret,0.09)))
                if random.random()<eret:
                    cash += e['seats']*e['price']
                else:
                    e['seats']=0
            e['age']+=1
        ents=[e for e in ents if e['seats']>0]
        # costs - Week24 support surge and D_S07 ad reallocation, then planned taper if stale tickets clear.
        if rel<=14: ops=348500.0
        elif rel<=35: ops=300000.0
        elif rel<=84: ops=190000.0
        else: ops=130000.0
        if rel<=35: dev=77900.0
        elif rel<=84: dev=65000.0
        else: dev=75000.0
        ads=50000.0
        if active_s2>0.94*cap: ads=47000.0
        capcost=28000.0
        # scale to tier7 if active enterprise seats create capacity risk.
        ent_seats=sum(e['seats'] for e in ents)
        if ent_seats>250000 or (active_s2*212 + ent_seats*120)>65000000:
            capcost=75000.0
        cash -= (ads+ops+dev+capcost)
        cash -= (leads+leads_extra)*0.5
        for c in cohorts:
            if c['n']>0: cash -= c['n']*plan_cost_per_day(c['group'],c['plan'])
        for e in ents:
            if e['seats']>0: cash -= e['seats']*ent_usage_cost_per_day(e)
        if random.random()<0.012: cash -= random.uniform(50000,350000)
    return cash, sum(c['n'] for c in cohorts if c['group']=='S2'), sum(c['n']*c['price'] for c in cohorts), sum(e['seats'] for e in ents)

